 78→type chatRequest struct {
 79→	Model          string        `json:"model"`
 80→	Messages       []chatMessage `json:"messages"`
 81→	ResponseFormat *respFormat   `json:"response_format,omitempty"`
 82→}
 83→
 84→type chatMessage struct {
 85→	Role    string `json:"role"`
 86→	Content string `json:"content"`
 87→}
 88→
 89→type respFormat struct {
 90→	Type string `json:"type"`
 91→}
 92→
 93→type chatResponse struct {
 94→	Choices []struct {
 95→		Message struct {
 96→			Content string `json:"content"`
 97→		} `json:"message"`
 98→	} `json:"choices"`
 99→	Error *struct {
100→		Message string `json:"message"`
101→	} `json:"error"`
102→}
