104→// Classify extracts structured metadata from the given content.
105→func (c *OpenAIClassifier) Classify(ctx context.Context, content string) (*Classification, error) {
106→	if content == "" {
107→		return nil, fmt.Errorf("provider: classify: empty input")
108→	}
109→
110→	// Truncate to avoid exceeding context window
111→	if len(content) > maxClassifyInputLen {
112→		content = content[:maxClassifyInputLen]
113→	}
114→
115→	body, err := json.Marshal(chatRequest{
116→		Model: c.model,
117→		Messages: []chatMessage{
118→			{Role: "system", Content: classifySystemPrompt},
119→			{Role: "user", Content: content},
120→		},
121→		ResponseFormat: &respFormat{Type: "json_object"},
122→	})
123→	if err != nil {
124→		return nil, fmt.Errorf("provider: classify: marshal request: %w", err)
125→	}
126→
127→	req, err := http.NewRequestWithContext(ctx, http.MethodPost, openAIChatURL, bytes.NewReader(body))
128→	if err != nil {
129→		return nil, fmt.Errorf("provider: classify: build request: %w", err)
130→	}
131→	req.Header.Set("Content-Type", "application/json")
132→	req.Header.Set("Authorization", "Bearer "+c.apiKey)
133→
134→	resp, err := c.client.Do(req)
135→	if err != nil {
136→		return nil, fmt.Errorf("provider: classify: http: %w", err)
137→	}
138→	defer func() { _ = resp.Body.Close() }()
139→
140→	respBody, err := io.ReadAll(resp.Body)
141→	if err != nil {
142→		return nil, fmt.Errorf("provider: classify: read response: %w", err)
143→	}
144→
145→	if resp.StatusCode != http.StatusOK {
146→		return nil, fmt.Errorf("provider: classify: api status %d: %s", resp.StatusCode, string(respBody))
147→	}
148→
149→	var result chatResponse
150→	if err := json.Unmarshal(respBody, &result); err != nil {
151→		return nil, fmt.Errorf("provider: classify: unmarshal response: %w", err)
152→	}
153→
154→	if result.Error != nil {
155→		return nil, fmt.Errorf("provider: classify: api error: %s", result.Error.Message)
156→	}
157→
158→	if len(result.Choices) == 0 || result.Choices[0].Message.Content == "" {
159→		return nil, fmt.Errorf("provider: classify: empty response from model")
160→	}
161→
162→	var classification Classification
163→	if err := json.Unmarshal([]byte(result.Choices[0].Message.Content), &classification); err != nil {
164→		return nil, fmt.Errorf("provider: classify: parse classification json: %w", err)
165→	}
166→
167→	return &classification, nil
168→}
