 14→	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
 15→		// Verify request
 16→		if r.Method != http.MethodPost {
 17→			t.Errorf("expected POST, got %s", r.Method)
 18→		}
 19→		if r.Header.Get("Authorization") != "Bearer test-key" {
 20→			t.Errorf("unexpected authorization header: %s", r.Header.Get("Authorization"))
 21→		}
 22→		if r.Header.Get("Content-Type") != "application/json" {
 23→			t.Errorf("unexpected content type: %s", r.Header.Get("Content-Type"))
 24→		}
 25→
 26→		var req embeddingRequest
 27→		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
 28→			t.Fatalf("failed to decode request: %v", err)
 29→		}
 30→		if req.Model != "text-embedding-3-small" {
 31→			t.Errorf("unexpected model: %s", req.Model)
 32→		}
 33→		if req.Input != "hello world" {
 34→			t.Errorf("unexpected input: %s", req.Input)
 35→		}
 36→
 37→		// Return a fake embedding
 38→		embedding := make([]float32, 1536)
 39→		embedding[0] = 0.1
 40→		embedding[1] = 0.2
 41→		embedding[2] = 0.3
 42→
 43→		resp := embeddingResponse{
 44→			Data: []struct {
 45→				Embedding []float32 `json:"embedding"`
 46→			}{
 47→				{Embedding: embedding},
 48→			},
 49→		}
 50→		w.Header().Set("Content-Type", "application/json")
 51→		_ = json.NewEncoder(w).Encode(resp)
 52→	}))
 53→	defer server.Close()
 54→
 55→	// Override the URL by using a custom client that rewrites URLs
 56→	embedder := NewOpenAIEmbedder("test-key",
 57→		WithEmbeddingHTTPClient(server.Client()),
 58→	)
 59→	// Override the URL for testing by replacing the const via a transport wrapper
 60→	origURL := openAIEmbeddingURL
 61→	_ = origURL // suppress unused warning
 62→
 63→	// Use a roundtrip wrapper to redirect to test server
 64→	embedder.client.Transport = &urlRewriter{
 65→		target:    server.URL,
 66→		transport: server.Client().Transport,
