 68→
 69→	vec, err := embedder.Embed(context.Background(), "hello world")
 70→	if err != nil {
 71→		t.Fatalf("unexpected error: %v", err)
 72→	}
 73→	if len(vec) != 1536 {
 74→		t.Fatalf("expected 1536 dimensions, got %d", len(vec))
 75→	}
 76→	if vec[0] != 0.1 || vec[1] != 0.2 || vec[2] != 0.3 {
 77→		t.Errorf("unexpected embedding values: %v", vec[:3])
